// Парсим входящее сообщение + прокидываем user_id в headers для auth gate.
// Поддерживаем /fetch <url>, /sub <channel>, и просто URL.
const msg = $('trigger_telegram').first().json.message;
const from = msg.from || {};
const user_id = from.id;
const chat_id = msg.chat.id;
const message_id = msg.message_id;
const text = (msg.text || msg.caption || '').trim();

let cmd = 'noop', url = '', extra = {};
const yt = text.match(/(https?:\/\/(?:www\.)?(?:youtube\.com\/(?:watch\?v=|shorts\/|embed\/)|youtu\.be\/)[0-9A-Za-z_-]{11}[^\s]*)/i);
const pipedUrl = text.match(/(https?:\/\/piped\.video\/[0-9A-Za-z_-]{11})/i);

if (text.startsWith('/fetch') || yt || pipedUrl) {
  cmd = 'fetch';
  url = (yt && yt[1]) || (pipedUrl && pipedUrl[1]) || text.replace(/^\/fetch\s*/i, '').trim();
} else if (text.startsWith('/start') || text.startsWith('/help')) {
  cmd = 'help';
}

return [{ json: {
  user_id, chat_id, message_id, cmd, url, raw: text,
  ts: new Date().toISOString(),
} }];

// Собираем payload для YandexGPT. v1.1: подгружаем user_profile из KB.
// Если /youtube_subs упал — идём в error-branch.
const meta = $('http_meta').first().json;
const subs = $('http_subs').first().json;
const ctx = $('code_parse').first().json;

if (subs.error) {
  return [{ json: { error_branch: true, error: subs.error,
                     hint: subs.hint || subs.last_err || 'см. логи Flask' } }];
}
// (опционально) HTTP-запрос к /user_profile через Code нельзя —
// делаем POST через следующий HTTP-узел. Здесь — только контекст.
const user_profile_summary = {
  markets: 'MOEX, СПБ Биржа',
  style: 'долгосрочный портфельный',
  tax_form: 'уточнить у PM: ИП/самозанятый/физлицо',
  horizon: '1-3 года',
};
const system = `Ты — персональный аналитик. Профиль пользователя: ${JSON.stringify(user_profile_summary)}.\n` +
  'Сделай по транскрипту: (1) summary 5 буллетов, (2) 3 action items, релевантные профилю.\n' +
  'Верни СТРОГО JSON: {"summary":["..."],"actions":[{"text":"...","subject":"...","trigger":"...","confidence":0.0-1.0}]}';

return [{ json: {
  ctx, // прокинем весь ctx (user_id, chat_id, message_id)
  video_id: meta.video_id || subs.video_id || '',
  url: ctx.url,
  title: meta.title || (subs.meta && subs.meta.title) || 'Без названия',
  channel: meta.channel || (subs.meta && subs.meta.uploader) || '',
  duration_sec: meta.duration_sec || (subs.meta && subs.meta.duration) || 0,
  published: meta.published || (subs.meta && subs.meta.uploadDate) || '',
  description: meta.description || (subs.meta && subs.meta.description) || '',
  subs_text: subs.text || '',
  subs_truncated: subs.truncated || false,
  subs_char_count: subs.char_count || 0,
  subs_lang: subs.lang || '?',
  system,
} }];

const yt = $('http_yagpt').first().json;
const ctx = $('code_build').first().json;
let summary = [];
let actions = [];
if (yt.parsed && yt.parsed.summary) summary = yt.parsed.summary;
if (yt.parsed && yt.parsed.actions) actions = yt.parsed.actions;
if (!summary.length && yt.raw) summary = [yt.raw.slice(0, 500)];
const claims = (ctx.subs_text || '').split('\n')
  .map(s => s.trim())
  .filter(s => s.length > 20 && s.length < 400)
  .slice(0, 30)
  .map(text => ({ text, ts_in_video: null, claim_type: 'transcript_chunk' }));
return [{ json: {
  ctx,
  video_id: ctx.video_id,
  url: ctx.url,
  title: ctx.title,
  meta: {
    'Канал': ctx.channel,
    'Длительность (сек)': ctx.duration_sec,
    'Дата публикации': ctx.published || 'н/д',
    'Язык субтитров': ctx.subs_lang,
    'Длина субтитров (симв)': ctx.subs_char_count,
    'YouTube': ctx.url,
  },
  summary, actions, claims,
  digest_id: ctx.video_id || ('d_' + Date.now()),
  cost: yt.usage || {},
  chunks: yt.chunks || 1,
  truncated: yt.truncated || false,
} }];
